/**
 * @ignore
 * @method
 * @name myriad#signOrderbookTypedData
 * @description EIP-712 signs an order-book typed-data message with the wallet private key (returns a 65-byte 0x signature)
 * @returns {string} the hex signature
 */
func (this *MyriadCore) SignOrderbookTypedData(types any, message any, networkId any) any {
	var chains any = this.SafeDict(this.Options, "chains", map[string]any{})
	var chainConfig any = this.SafeDict(chains, networkId, map[string]any{})
	var exchangeAddress any = this.SafeString(chainConfig, "obExchangeAddress")
	if ccxt.IsTrue(ccxt.IsEqual(exchangeAddress, nil)) {
		panic(ccxt.NotSupported(ccxt.Add(ccxt.Add(this.Id, " order book trading is not configured for network "), networkId)))
	}
	var domainName any = this.SafeString(this.Options, "obDomainName", "MyriadCTFExchange")
	var domainVersion any = this.SafeString(this.Options, "obDomainVersion", "1")
	var domain any = map[string]any{
		"name":              domainName,
		"version":           domainVersion,
		"chainId":           this.ParseToInt(networkId),
		"verifyingContract": exchangeAddress,
	}
	var encoded any = this.EthEncodeStructuredData(domain, types, message)
	var digest any = this.Hash(encoded, ccxt.Keccak, "hex")
	var signature any = ccxt.Ecdsa(digest, this.Remove0xPrefix(this.PrivateKey), ccxt.Secp256k1, nil)
	var rRaw any = ccxt.GetValue(signature, "r")
	var sRaw any = ccxt.GetValue(signature, "s")
	var r any = ccxt.PadStart(rRaw, 64, "0")
	var s any = ccxt.PadStart(sRaw, 64, "0")
	var v any = this.Sum(27, ccxt.GetValue(signature, "v"))
	var sigHex any = ccxt.Add(ccxt.Add(ccxt.Add("0x", r), s), this.IntToBase16(v))
	return ccxt.ToLower(sigHex)
}

